import { createClient, LiveMap } from "@liveblocks/client";
import { createRoomContext } from "@liveblocks/react";

const client = createClient({
  authEndpoint: "/api/liveblocks-auth",
});

type Presence = {};

type Storage = {
  pixels: LiveMap<string, string>;
};

type UserMeta = {};
type RoomEvent = never;
type ThreadMetadata = never;

export const {
  suspense: {
    RoomProvider,
    useStorage,
    useMutation,
  },
} = createRoomContext<Presence, Storage, UserMeta, RoomEvent>(client);

import { Liveblocks } from "@liveblocks/node";
import { NextRequest } from "next/server";

const liveblocks = new Liveblocks({
  secret: process.env.LIVEBLOCKS_SECRET_KEY!,
});

export async function POST(request: NextRequest) {
  const session = liveblocks.prepareSession(`user-${Math.random()}`, {
    userInfo: {},
  });

  const { room } = await request.json();
  session.allow(room, session.FULL_ACCESS);

  const { status, body } = await session.authorize();
  return new Response(body, { status });
}

"use client";

import { useRef } from "react";
import { LiveMap } from "@liveblocks/client";
import { useStorage, useMutation } from "../../liveblocks.config";

export default function PixelGrid() {
  const colorPickerRef = useRef<HTMLInputElement>(null);

  const pixels = useStorage((root) => root.pixels);

  const paintPixel = useMutation(({ storage }, key: string, color: string) => {
    storage.get("pixels").set(key, color);
  }, []);

  const clearGrid = useMutation(({ storage }) => {
    const pixelsMap = storage.get("pixels");
    for (const key of Array.from(pixelsMap.keys())) {
      pixelsMap.delete(key);
    }
  }, []);

  const handlePixelClick = (row: number, col: number) => {
    const color = colorPickerRef.current?.value ?? "#000000";
    paintPixel(`${row},${col}`, color);
  };

  const cells: JSX.Element[] = [];
  for (let r = 0; r < 8; r++) {
    for (let c = 0; c < 8; c++) {
      const key = `${r},${c}`;
      const color = pixels?.get(key) ?? "";
      cells.push(
        <button
          key={key}
          data-pixel={key}
          data-color={color}
          onClick={() => handlePixelClick(r, c)}
          style={{
            width: "60px",
            height: "60px",
            backgroundColor: color || "#ffffff",
            border: "1px solid #ccc",
            cursor: "pointer",
          }}
        />
      );
    }
  }

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "16px", padding: "24px" }}>
      <h1>Collaborative Pixel Grid</h1>
      <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
        <label htmlFor="pixel-color">Color:</label>
        <input
          id="pixel-color"
          type="color"
          defaultValue="#ff0000"
          ref={colorPickerRef}
        />
        <button
          id="clear-grid"
          onClick={clearGrid}
          style={{ padding: "8px 16px", cursor: "pointer" }}
        >
          Clear Grid
        </button>
      </div>
      <div
        id="pixel-grid"
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(8, 60px)",
          gap: "2px",
        }}
      >
        {cells}
      </div>
    </div>
  );
}

