  return (
    <RoomProvider
      id={roomId}
      initialPresence={{}}
      initialStorage={{
        pixels: new LiveMap<string, string>(),
      }}
    >
      <Suspense fallback={<div>Loading...</div>}>
        <PixelGrid />
      </Suspense>
    </RoomProvider>
  );
}

